// /frontend/src/components/Community.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import Composer from "./Composer";
import Post from "./Post";

const LS_KEY = "wx:xstyle:v1";
const MAX_LEN = 280;

function seedData(city = "Atlanta, GA") {
  return [
    {
      id: crypto.randomUUID(),
      author: { name: "Maya", handle: "maya_wx", avatar: "" },
      city,
      text: "Sky just cleared over Midtown — rainbow by the park 🌈 Anyone else see it?",
      createdAt: Date.now() - 1000 * 60 * 12,
      likes: 12,
      reposts: 3,
      replies: [
        {
          id: crypto.randomUUID(),
          author: { name: "Leo", handle: "leo_runs", avatar: "" },
          text: "Yep! Snapped a pic after my run.",
          createdAt: Date.now() - 1000 * 60 * 9,
          likes: 2,
        },
      ],
      youLiked: false,
      youReposted: false,
    },
    {
      id: crypto.randomUUID(),
      author: { name: "Sam", handle: "samwx", avatar: "" },
      city: "Athens, GA",
      text: "Super muggy tonight. If you’re going for a jog, bring water 💦",
      createdAt: Date.now() - 1000 * 60 * 45,
      likes: 6,
      reposts: 1,
      replies: [],
      youLiked: false,
      youReposted: false,
    },
  ];
}

function load() {
  try {
    const raw = localStorage.getItem(LS_KEY);
    if (raw) return JSON.parse(raw);
  } catch {}
  const seed = seedData();
  localStorage.setItem(LS_KEY, JSON.stringify(seed));
  return seed;
}

function save(posts) {
  try { localStorage.setItem(LS_KEY, JSON.stringify(posts)); } catch {}
}

const tabs = ["For You", "Following", "City"];

export default function Community({ defaultCity = "Atlanta, GA" }) {
  const [activeTab, setActiveTab] = useState("For You");
  const [cityFilter, setCityFilter] = useState(defaultCity);
  const [posts, setPosts] = useState(load);
  const listRef = useRef(null);

  useEffect(() => save(posts), [posts]);

  // basic “following” demo list — swap with backend later
  const followingHandles = useMemo(() => new Set(["maya_wx", "leo_runs"]), []);

  const timeline = useMemo(() => {
    let arr = [...posts];
    if (activeTab === "Following") {
      arr = arr.filter(p => followingHandles.has(p.author.handle));
    } else if (activeTab === "City") {
      arr = arr.filter(p => p.city.toLowerCase().includes(cityFilter.toLowerCase()));
    }
    // “For You” = lightly boost engagement
    if (activeTab === "For You") {
      arr.sort((a, b) => (b.likes + b.reposts * 2) - (a.likes + a.reposts * 2) || b.createdAt - a.createdAt);
    } else {
      arr.sort((a, b) => b.createdAt - a.createdAt);
    }
    return arr;
  }, [activeTab, cityFilter, posts, followingHandles]);

  // actions
  const postNew = (text) => {
    const p = {
      id: crypto.randomUUID(),
      author: { name: "You", handle: "you", avatar: "" },
      city: cityFilter,
      text: text.slice(0, MAX_LEN),
      createdAt: Date.now(),
      likes: 0,
      reposts: 0,
      replies: [],
      youLiked: false,
      youReposted: false,
    };
    setPosts([p, ...posts]);
    // jump to top
    listRef.current?.scrollTo({ top: 0, behavior: "smooth" });
  };

  const like = (id) => {
    setPosts(ps => ps.map(p => {
      if (p.id !== id) return p;
      const youLiked = !p.youLiked;
      return { ...p, youLiked, likes: Math.max(0, p.likes + (youLiked ? 1 : -1)) };
    }));
  };

  const repost = (id) => {
    setPosts(ps => ps.map(p => {
      if (p.id !== id) return p;
      const youReposted = !p.youReposted;
      return { ...p, youReposted, reposts: Math.max(0, p.reposts + (youReposted ? 1 : -1)) };
    }));
  };

  const reply = (id, text) => {
    setPosts(ps => ps.map(p => {
      if (p.id !== id) return p;
      const r = {
        id: crypto.randomUUID(),
        author: { name: "You", handle: "you", avatar: "" },
        text: text.slice(0, MAX_LEN),
        createdAt: Date.now(),
        likes: 0,
      };
      return { ...p, replies: [...p.replies, r] };
    }));
  };

  return (
    <div className="rounded-2xl backdrop-blur-xl bg-black/40 ring-1 ring-white/10 overflow-hidden">
      {/* Header */}
      <div className="px-4 pt-3 pb-2 flex items-center justify-between gap-2">
        <div className="text-sm opacity-80">Community</div>
        <input
          value={cityFilter}
          onChange={(e) => setCityFilter(e.target.value)}
          className="bg-white/10 px-3 py-2 rounded-lg text-sm outline-none"
          placeholder="Filter by city…"
        />
      </div>

      {/* Tabs like X */}
      <div className="px-2 flex">
        {tabs.map(t => (
          <button
            key={t}
            onClick={() => setActiveTab(t)}
            className={`flex-1 py-2 rounded-lg text-sm ${
              activeTab === t ? "bg-white/15" : "hover:bg-white/10"
            }`}
          >
            {t}
          </button>
        ))}
      </div>

      {/* Composer */}
      <div className="px-3 pb-2 pt-3 border-t border-white/10">
        <Composer maxLen={MAX_LEN} onPost={postNew} placeholder={`What's the weather like in ${cityFilter}?`} />
      </div>

      {/* Timeline */}
      <div ref={listRef} className="max-h-[60vh] overflow-y-auto divide-y divide-white/10">
        {timeline.map(p => (
          <Post
            key={p.id}
            post={p}
            onLike={() => like(p.id)}
            onRepost={() => repost(p.id)}
            onReply={(text) => reply(p.id, text)}
          />
        ))}
        {!timeline.length && (
          <div className="py-10 text-center text-sm opacity-70">No posts yet. Be the first!</div>
        )}
      </div>
    </div>
  );
}
